import React, { useRef, useEffect } from 'react';

export default function SparklesBackground({
  particleCount = 120,
  minSize = 1,
  maxSize = 4,
  particleColor = "#ffffff"
}) {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    let animationFrameId;

    const resizeCanvas = () => {
      canvas.width = canvas.parentElement.clientWidth;
      canvas.height = canvas.parentElement.clientHeight;
    };
    resizeCanvas();
    window.addEventListener('resize', resizeCanvas);

    // Particle structure definition
    class Particle {
      constructor() {
        this.reset(true);
      }

      reset(init = false) {
        this.x = Math.random() * canvas.width;
        // If initial load, scatter y coordinates. Otherwise, place at bottom.
        this.y = init ? Math.random() * canvas.height : canvas.height + 10;
        this.size = Math.random() * (maxSize - minSize) + minSize;
        this.speedY = -(Math.random() * 0.5 + 0.1);
        this.speedX = (Math.random() - 0.5) * 0.1;
        this.opacity = Math.random();
        this.fadeSpeed = Math.random() * 0.02 + 0.005;
        this.fadingOut = Math.random() > 0.5;
      }

      update() {
        this.y += this.speedY;
        this.x += this.speedX;

        // Twinkle effect (fade opacity up/down)
        if (this.fadingOut) {
          this.opacity -= this.fadeSpeed;
          if (this.opacity <= 0.1) {
            this.opacity = 0.1;
            this.fadingOut = false;
          }
        } else {
          this.opacity += this.fadeSpeed;
          if (this.opacity >= 0.9) {
            this.opacity = 0.9;
            this.fadingOut = true;
          }
        }

        // Reset if float off-screen
        if (this.y < -10 || this.x < -10 || this.x > canvas.width + 10) {
          this.reset(false);
        }
      }

      draw() {
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fillStyle = particleColor;
        ctx.globalAlpha = this.opacity;
        ctx.fill();
      }
    }

    const particles = Array.from({ length: particleCount }, () => new Particle());

    const render = () => {
      // Clear canvas
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Update and draw particles
      particles.forEach(p => {
        p.update();
        p.draw();
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      cancelAnimationFrame(animationFrameId);
      window.removeEventListener('resize', resizeCanvas);
    };
  }, [particleCount, minSize, maxSize, particleColor]);

  return (
    <div className="relative w-full h-full min-h-screen bg-neutral-950 overflow-hidden">
      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full block" />
    </div>
  );
}
